ALTER TABLE "creator_photos" ADD FOREIGN KEY ("creator_id") REFERENCES "creators" ("id") ON DELETE CASCADE;
ALTER TABLE "creator_photos" ADD FOREIGN KEY ("image_id") REFERENCES "images" ("id");
