CREATE TABLE "collaborations" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "application_id" INT NOT NULL,
  "event_id" INT NOT NULL,
  "creator_user_id" INT NOT NULL,
  "venue_user_id" INT NOT NULL,
  "status" VARCHAR(20) DEFAULT 'pending',
  "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  CHECK (status IN ('pending', 'completed', 'cancelled'))
);

CREATE INDEX idx_collaborations_creator ON collaborations(creator_user_id);
CREATE INDEX idx_collaborations_venue ON collaborations(venue_user_id);

ALTER TABLE "collaborations" ADD FOREIGN KEY ("application_id") REFERENCES "applications" ("id") ON DELETE CASCADE;
ALTER TABLE "collaborations" ADD FOREIGN KEY ("event_id") REFERENCES "events" ("id") ON DELETE CASCADE;
ALTER TABLE "collaborations" ADD FOREIGN KEY ("creator_user_id") REFERENCES "users" ("id") ON DELETE CASCADE;
ALTER TABLE "collaborations" ADD FOREIGN KEY ("venue_user_id") REFERENCES "users" ("id") ON DELETE CASCADE;